INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('field3d_timed_oneshot_reveal_unbound_to_narration', 'field_3d scenario one-shots (current flip / glyph ⊗→⊙ / velocity compass / split-screen switch / camera tilt / F-appear) fired at a hardcoded *_at_ms guess, 7–31s off the sentence that narrates them (worse after the Rule-31 pacing trims)', 'MAJOR', 'peter_parker:renderer_primitives', 'Every field_3d scenario one-shot was gated on a hand-picked state-local millisecond constant (fcw current_flip.reverse_at_ms=20000; rhr glyph_toggle_at_ms=5000 + camera_orbit from t=0; no_work split_compare.sequential_delay_ms=7000 + velocity_compass_at_ms=18000 + f_appear). These constants were never tuned against the narration timeline, and the Rule-31 pacing pass changed the narration lengths without touching them, so each event landed far from its line: fcw STATE_1 flipped at 20s but "Watch the current flip" is spoken at ~41s; no_work STATE_3 froze the electric side + revealed the magnetic charge at exactly 7s, the instant the voice says "watch the speed meter climb"; rhr STATE_3 flipped the cross→dot at 5s but "watch what happens if I flip it" plays at ~27s. Reveals ride the sim clock while audio is a passenger (Rule 26), which is correct for per-sentence glow/math/hand cues (those ARE sentence-bound), but the scenario one-shots had no equivalent binding — they were pure fixed-time. Telugu (~1.2–1.3x longer) shifted the sentences further from the fixed reveals.', 'A scenario one-shot that a sentence NARRATES ("watch it flip / tilt / drop in") must be BOUND to that sentence, not a hardcoded *_at_ms. Tag the narrating tts_sentence with `scenario_cue` (current_flip | glyph_toggle | velocity_compass | split_switch | camera_orbit | f_appear); the review player posts SET_CUE_TIME with that sentence\u0027s per-language start and field_3d_renderer.cueTriggerMs(name, fallback) overrides the *_at_ms. Keep the *_at_ms as the THE-EYE / no-cue fallback (deterministic gate sends no cues). Never leave a narrated event on a bare fixed-ms trigger.', 'manual', 'Play each guided state with narration on: the sentence that says "watch the X" must coincide (\u00b12s) with X actually happening on screen — the flip/glyph/compass/split-switch/tilt fires as the line is spoken, never seconds before or after. Switch language to Telugu and re-check: the event must still land on its (now longer) sentence, proving the trigger follows narration not a fixed clock. A one-shot that fires at a constant sim time regardless of which sentence is playing is the regression.', 'FIXED', ARRAY['magnetic_force_moving_charge', 'magnetic_force_direction_right_hand_rule', 'magnetic_force_perpendicular_no_work', 'force_on_current_carrying_wire'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/scripts/build_review_site.ts', 'src/data/concepts/force_on_current_carrying_wire.json', 'src/data/concepts/magnetic_force_direction_right_hand_rule.json', 'src/data/concepts/magnetic_force_perpendicular_no_work.json'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_state_duration_field_clamps_eye_capture_window', 'The per-state `duration` field (24–30s) understates real narration (37–51s), and deriveStateMeta clamps THE EYE dense-capture to it — so the frames where the sync desyncs live were never photographed', 'MAJOR', 'alex:json_author', 'deriveStateDurationsMs() in deriveStateMeta.ts reads each state\u0027s authored `duration` (seconds), converts to ms and clamps to [3000, 30000]; that window is what THE EYE / smoke:visual-validator --dense captures. Every batch-1 state declared a duration well under its real narration length (e.g. fcw STATE_1 declares 30 but runs ~51s, rhr STATE_2 declares 30 but ~46s EN / ~59s TE). So the payoff sentences — and the one-shot desyncs they expose — fall OUTSIDE THE EYE\u0027s own capture window. This is why the mandatory visual gate (CLAUDE.md \u00a75\u2462) never caught the timing bug. The live player is unaffected (it paces off the real per-sentence timeline, not `duration`).', 'Author each state\u0027s `duration` to at least its real narration length (estimate words/2.5 + sentences, or read the rendered clip totals once TTS exists) so THE EYE dense-capture spans the FULL spoken window including the closing/payoff sentence. A `duration` shorter than the narration silently blinds the visual gate — treat duration as the capture-window contract, not a cosmetic label. Consider raising DURATION_MAX_MS or driving the capture window off the narration timeline.', 'js_eval', 'For each state, assert authored duration_ms >= estimated narration ms (words/2.5 + sentences, \u00d70.82) so the dense-capture window covers the last sentence. Flag any state whose declared duration is < 0.8\u00d7 its narration length as an EYE blind spot.', 'FIXED', ARRAY['magnetic_force_moving_charge', 'magnetic_force_direction_right_hand_rule', 'magnetic_force_perpendicular_no_work', 'force_on_current_carrying_wire'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts', 'src/lib/validators/visual/screenshotter.ts', 'src/data/concepts/magnetic_force_moving_charge.json', 'src/data/concepts/magnetic_force_direction_right_hand_rule.json', 'src/data/concepts/magnetic_force_perpendicular_no_work.json', 'src/data/concepts/force_on_current_carrying_wire.json'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_fcw_rhr_hand_static_after_current_flip', 'force_on_current_wire STATE_1 3D right-hand is oriented ONCE at state entry and never re-computed, so after the current flip the thumb points the OLD (now wrong) way while the voice says "your thumb points along F"', 'MAJOR', 'peter_parker:renderer_primitives', 'In applyForceWireState the fcw hand (fcw_hand) has its forward direction baked once (lU=+x, fU=lU\u00d7bU); the per-frame block updates fcw_current_arrow / fcw_F_net / fcw_carrier(_force) but never fcw_hand. After the current reverses, the current cones and green F-arrow flip but the static hand\u0027s thumb keeps pointing the original direction — a visible physics contradiction during the RHR walkthrough narration. (Binding the flip to its sentence via the new cue channel moves the flip to ~41s AFTER the walkthrough, so the hand is correct DURING s1_5\u2013s1_7; the residual is the ~10s after s1_8\u2019s flip.)', 'A static right-hand prop on a state that can reverse its current/field must re-orient (or hide/dim) when the direction flips — recompute the thumb from the LIVE current direction each frame (like lorentz_hand), or fade the hand out at the flip. Never leave a baked hand pointing a direction the scene has since reversed.', 'manual', 'On fcw STATE_1, let the current flip: the 3D hand\u2019s thumb must track the NEW force direction (or the hand must fade) — a thumb still pointing the pre-flip way while the green F-arrow points the other way is the bug.', 'FIXED', ARRAY['force_on_current_carrying_wire'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_moving_charge_velocity_decomposition_never_enabled', 'magnetic_force_moving_charge STATE_4 narrates the v-parallel/v-perp split ("part of v drifts along B, the rest circles") but the pre-built decomposition arrows are never switched on — a regression from the 8\u21924 Rule-31 restructure', 'MAJOR', 'alex:json_author', 'The renderer builds vParArrow/vPerpArrow + "v cos \u03b8"/"v sin \u03b8" labels for the helix decomposition, shown only when extras.vector_decomposition.show is true. STATE_4\u2019s extras (velocity_vector / force_vector / particle_trail) never declare vector_decomposition, so the arrows stay hidden while s4_3 explains exactly that split. The decomposition visual was wired to the old standalone STATE_3 and lost when 8 states collapsed to 4.', 'When a state\u2019s narration names a decomposition/vector that a pre-built primitive exists for, the state extras MUST enable it (or the sentence must be cut). After any state-count restructure, re-check every narrated visual promise against the state\u2019s enabled primitives — a sentence with no on-screen counterpart is a regression.', 'manual', 'On moving_charge STATE_4, when s4_3 says "part of v drifts along B, the rest circles" the v-parallel and v-perpendicular arrows must be visible on the helix. If nothing decomposes on screen, the promise is unshown.', 'FIXED', ARRAY['magnetic_force_moving_charge'], ARRAY['src/data/concepts/magnetic_force_moving_charge.json'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_lorentz_trail_dots_narrated_as_continuous_line', 'magnetic_force_moving_charge STATE_2 narrates "watch the trail dots — equally spaced" but the lorentz trail renders as a smooth continuous line (no dot markers), so the visual cannot demonstrate the constant-speed claim', 'MODERATE', 'peter_parker:renderer_primitives', 'The lorentz_force_uniform_field trail is a single THREE.Line; there are no discrete equally-spaced point markers in this scenario (extras.particle_trail.equal_arc is read only by magnetic_no_work\u2019s nwUpdateTrail, not by the lorentz path). A smooth line looks identical whether or not the speed is constant, so "equally spaced dots" has nothing to point at. The sibling no_work scenario has a purpose-built velocity-compass for this proof; lorentz has no equivalent.', 'If a sentence points at "dots / equally-spaced markers" as proof, the scenario must actually render discrete equal-arc/equal-time markers — reuse the no_work equal-time marker device, or reword the narration to describe the smooth circle. Do not narrate a discrete visual the renderer draws as continuous.', 'manual', 'On moving_charge STATE_2, "watch the trail dots — equally spaced" must have visible discrete equally-spaced markers on the orbit. A smooth unbroken trail line under that line is the mismatch.', 'FIXED', ARRAY['magnetic_force_moving_charge'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_rhr_missing_glow_tags_no_narration_emphasis', 'magnetic_force_direction_right_hand_rule has ZERO `glow` tags across all states — nothing brightens when the narration names velocity v / magnetic field B / force F, so the eye is never directed (the renderer\u2019s per-vector glow machinery is never invoked)', 'MODERATE', 'alex:json_author', 'applyRhrForceDirectionGlow() reads glowTargets to brighten the focal v/f/b/hand element (Rule 29), but no tts_sentence in the concept carries a `glow` field. The sibling magnetic_force_moving_charge uses glow throughout its RHR beat. So across the rhr sim, when the voice says "point your fingers along velocity v" / "curl toward magnetic field B" / "the thumb gives F", nothing on screen lifts to match — a systemic narration\u2194emphasis gap, not a timing slip.', 'Every RHR/cross-product state must glow the focal vector on the sentence that names it (glow: "v"/"b"/"f"/"hand" per Rule 29), mirroring magnetic_force_moving_charge. A concept teaching directions with no glow tags fails the emphasis-tracks-narration check.', 'manual', 'Scrub rhr states: as each sentence names v, B, F or the hand, the matching scene element must brighten while peers dim. If nothing ever glows across the whole concept, the glow tags are missing.', 'FIXED', ARRAY['magnetic_force_direction_right_hand_rule'], ARRAY['src/data/concepts/magnetic_force_direction_right_hand_rule.json'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_fcw_static_formula_overlay_spoils_derivation', 'force_on_current_wire STATE_2 shows the fully-collapsed answer card F=(nAL)(qv_dB)=(nAqv_d)(LB)=ILB from t=0 in one corner, while the equation_panel spends ~22s "deriving" the same result the student can already read', 'MODERATE', 'alex:json_author', 'The renderer sets stateDef.formula_overlay unconditionally on state entry (static bottom-right card), but STATE_2\u2019s designed aha is the progressive SET_MATH build of the same collapse in the bottom-left equation_panel. Showing the final F=ILB from the first frame undercuts the "the messy carrier picture collapses into one clean law" moment.', 'Do not show a static formula_overlay of the FINAL result on a state whose aha is deriving that result. Either drop the overlay and rely on the TTS-synced equation_panel, or gate the overlay to appear only after the last derivation step is spoken.', 'manual', 'On fcw STATE_2, the fully-collapsed F=ILB must NOT be visible before the derivation narration reaches it. A final-answer card present from t=0 while the equation_panel is still building is the spoiler.', 'FIXED', ARRAY['force_on_current_carrying_wire'], ARRAY['src/data/concepts/force_on_current_carrying_wire.json'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_glow_target_wrong_trail_vs_sliders', 'magnetic_force_moving_charge STATE_1 CTA "drag the angle slider" glows "trail" instead of "sliders" — the trail line pulses while the teacher is told to touch the control panel', 'MODERATE', 'alex:json_author', 'The slider-CTA sentence (s1_2c) carries glow:"trail"; the structurally identical CTAs in STATE_2 (s2_6) and STATE_4 (s4_4) correctly glow "sliders" (a real target that pulses the #sliders panel). So the wrong element is emphasised on the "drag the slider" beat.', 'A "drag/adjust the <control>" sentence must glow "sliders" (the control panel), not the resulting visual. Keep glow targets consistent across the same CTA pattern within a concept.', 'manual', 'On moving_charge STATE_1, the "drag the angle slider" line must pulse the slider panel, not the trail. A pulsing trail on a control CTA is the wrong target.', 'FIXED', ARRAY['magnetic_force_moving_charge'], ARRAY['src/data/concepts/magnetic_force_moving_charge.json'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_teacher_script_mirror_stale_deadcode', 'field_3d_config.states[*].teacher_script mirror copies are dead code (read by neither the player nor the renderer) yet drifted from the authoritative epic_l_path — missing Rule 30 bare-symbol expansion in several sentences', 'MODERATE', 'alex:json_author', 'Both the review player (build_review_site.ts) and field_3d_renderer.ts read narration ONLY from epic_l_path.states[*].teacher_script; the field_3d_config mirror is never consumed. In rhr and no_work the mirror has drifted (8/21 rhr sentences differ; no_work s4_2), keeping "along v" / "toward B" instead of the epic_l "along velocity v" / "toward magnetic field B" (Rule 30). Harmless today (dead), but a future reader/consumer would be misled.', 'Do not keep a second copy of the narration that nothing reads. Either delete field_3d_config.states[*].teacher_script or keep it byte-identical to epic_l_path. One source of truth for narration (epic_l_path).', 'js_eval', 'For each concept, assert field_3d_config.states[*].teacher_script (if present) matches epic_l_path.states[*].teacher_script sentence-for-sentence, or is absent. Any divergence is stale dead narration.', 'FIXED', ARRAY['magnetic_force_direction_right_hand_rule', 'magnetic_force_perpendicular_no_work'], ARRAY['src/data/concepts/magnetic_force_direction_right_hand_rule.json', 'src/data/concepts/magnetic_force_perpendicular_no_work.json'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_dense_capture_freeruns_lags_eye', 'THE EYE dense capture free-ran the sim on a WALL-clock cadence, so sim-time lagged ~0.6x (each screenshot stalls rAF) and the narration tail was never photographed — late one-shots (fcw flip at sim-20s, no_work compass at sim-18s) fell outside every dense frame', 'MAJOR', 'peter_parker:visual_validator', 'captureDenseSeries (src/lib/validators/visual/screenshotter.ts) advanced between dense frames with page.waitForTimeout at WALL-clock intervals while the sim free-ran; each Playwright locator.screenshot stalls the page rAF loop, so the renderer frame-count clock (time += 0.016/frame) advanced only ~0.6x wall-clock. A state whose narration runs ~50s therefore only reached ~30s of SIM-time inside its dense window, so late narration beats were never captured. Raising the duration caps (the …duration_field_clamps… fix) widened the wall-clock window but not the sim-time reached, so it was necessary-but-not-sufficient. This is why the fcw-hand-flip and no_work-split scars carried manual probes: THE EYE structurally could not see the beat.', 'Dense frames on a renderer with a sim-clock (field_3d, window.PM_simTimeMs) must be PINNED to evenly spaced SIM-time targets — crawl-and-fill via SET_TIME_FREEZE + pollSimTimeReached (the same pin+poll the frozen frame uses), never wall-clock free-run. SET_TIME_FREEZE advances one rAF frame at a time so per-frame accumulators (trail, equal-arc dots, current drift) fill deterministically; SET_TIME_JUMP must NOT be used (it does not accumulate). Renderers without PM_simTimeMs keep the wall-clock fallback so they never burn a poll cap. Dense is never baselined, so re-timing needs no baseline re-approval.', 'manual', 'Run visual:eyes on a concept with a late one-shot (fcw current_flip fallback reverse_at_ms=20000): the dense frames near sim-20s MUST show the flipped state (cones + F + hand reversed). If no dense frame ever reaches the authored sim-time of the late beat, dense is free-running/lagging again.', 'FIXED', ARRAY['magnetic_force_moving_charge', 'magnetic_force_direction_right_hand_rule', 'magnetic_force_perpendicular_no_work', 'force_on_current_carrying_wire'], ARRAY['src/lib/validators/visual/screenshotter.ts'], 'session_2026-07-03_ch4_sync_audit', 'incident'),
('field3d_stored_tts_clip_stale_after_text_rewrite_same_id', 'Stored Sarvam mp3s keyed by sentence id survive a text rewrite — the retrofitted sims SPEAK the old Socratic script while the captions + choreography follow the new JSON (fcw STATE_5 narrates the bent/zigzag wire, the last state narrates closing the loop)', 'CRITICAL', 'peter_parker:renderer_primitives', 'generate_tts_audio.ts skipped a clip whenever its mp3 already existed on disk (existsSync(abs) && !force) — identity was the FILENAME (sentenceId_lang.mp3), never the text. The Socratic\u2192straightforward retrofit rewrote every sentence under the SAME ids (s1_1, s5_2, \u2026) and compressed fcw from 7 states to 6 (content shifted up one slot), so the old recordings matched the new keys positionally and kept playing: audio = old script, captions = new JSON text, choreography = new cues. build_review_site.ts compounded it by wiring any manifest clip without checking it against the current sentence text, and warning only when the manifest was entirely MISSING, never when stale. Even re-running tts:generate was a no-op without --force (and would have overwritten the manifest chars with the new lengths, destroying the staleness evidence). 27/31 fcw EN sentences were stale + 3 unvoiced + 19 orphans (incl. all s*_pred Socratic clips and old STATE_7); rhr 17 stale, mfmc 9 stale + 8 unvoiced, no_work 13 stale; electric_dipole_in_field had 2 latent stale clips from the live-instrument conversion.', 'A stored narration clip\u0027s identity is its TEXT, not its filename. generate_tts_audio.ts now records sha1 text_hash per clip in the manifest and re-fetches whenever the current sentence text no longer hashes to it (chars-length fallback for pre-hash manifests), and prunes orphan mp3s whose sentence ids left the JSON. build_review_site.ts refuses to wire a clip whose recorded text no longer matches the JSON — stale clips are MUTED with a loud per-concept warning naming them (silence under a correct caption beats the wrong voice). After ANY teacher_script text edit, re-run npm run tts:generate <id> before handoff.', 'js_eval', 'For every tts_sentence \u00d7 lang with an available manifest clip, assert sha1(trim(text_lang)) === clip.text_hash (fallback: trim-length === clip.chars). Any mismatch = the sim speaks a different script than it captions. Also assert no mp3 in review-site/<id>/audio/ lacks a matching sentence id in the concept JSON.', 'FIXED', ARRAY['magnetic_force_moving_charge', 'magnetic_force_direction_right_hand_rule', 'magnetic_force_perpendicular_no_work', 'force_on_current_carrying_wire', 'electric_dipole_in_field'], ARRAY['src/scripts/generate_tts_audio.ts', 'src/scripts/build_review_site.ts'], 'session_2026-07-03_ch4_sync_audit', 'incident')
